import{_ as o}from"./chunks/文件受限图.DsG20F9s.js";import{_ as a,o as t,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Moderace obrázků a režim přístupu","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Safety/image-moderation-and-access-mode.md","filePath":"cs-CZ/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),i={name:"cs-CZ/Safety/image-moderation-and-access-mode.md"};function d(l,e,s,u,p,m){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="moderace-obrazku-a-rezim-pristupu" tabindex="-1">Moderace obrázků a režim přístupu <a class="header-anchor" href="#moderace-obrazku-a-rezim-pristupu" aria-label="Permalink to &quot;Moderace obrázků a režim přístupu&quot;">​</a></h1><p>Moderace obrázků přiřazuje nahraným obrázkům věkové hodnocení. Režim přístupu určuje, která hodnocení jsou veřejně viditelná.</p><p>Ovlivňuje to veřejnou galerii, veřejné URL souborů a Random Image API. Neomezuje administraci. Administrátoři mohou stále vidět a spravovat všechny soubory.</p><h2 id="kde-nastavit" tabindex="-1">Kde nastavit <a class="header-anchor" href="#kde-nastavit" aria-label="Permalink to &quot;Kde nastavit&quot;">​</a></h2><p>Otevřete administraci a přejděte na:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>Hlavní nastavení jsou:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="co-dela-access-mode" tabindex="-1">Co dělá Access Mode <a class="header-anchor" href="#co-dela-access-mode" aria-label="Permalink to &quot;Co dělá Access Mode&quot;">​</a></h2><p>Access mode určuje, která věková hodnocení mohou být veřejně zobrazena.</p><p>Aktuální režimy:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Veřejně viditelná hodnocení</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>Pouze General</td></tr></tbody></table><p>Výchozí je Adult mode.</p><p>Pro soukromé weby nebo weby s dospělým obsahem může být Adult mode vhodný. Pro opatrnější veřejnou galerii zvolte Youth, Teen nebo Child mode.</p><h2 id="co-znamena-zapnuti-moderace" tabindex="-1">Co znamená zapnutí moderace <a class="header-anchor" href="#co-znamena-zapnuti-moderace" aria-label="Permalink to &quot;Co znamená zapnutí moderace&quot;">​</a></h2><p>Když je moderace zapnutá, ImgBed při uploadu zavolá vybraného poskytovatele moderace a uloží zjištěné věkové hodnocení.</p><p>Hlavní hodnocení:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Význam</th></tr></thead><tbody><tr><td>General</td><td>Bezpečný veřejný obsah</td></tr><tr><td>R12</td><td>Mírně citlivý obsah</td></tr><tr><td>R16</td><td>Středně citlivý obsah</td></tr><tr><td>R18</td><td>Obsah pro dospělé</td></tr></tbody></table><p>Výsledek moderace se používá při rozhodování o veřejném přístupu.</p><p>Pokud moderace není zapnutá nebo staré soubory nemají rating, považují se za neohodnocené. Neohodnocené soubory nejsou automaticky odstraněny z veřejné galerie ani Random Image API jen proto, že nemají výsledek moderace.</p><h2 id="vyber-poskytovatele-moderace" tabindex="-1">Výběr poskytovatele moderace <a class="header-anchor" href="#vyber-poskytovatele-moderace" aria-label="Permalink to &quot;Výběr poskytovatele moderace&quot;">​</a></h2><p>Dostupní poskytovatelé zahrnují:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>Každý poskytovatel má jiné požadavky:</p><ul><li>moderatecontent.com obvykle vyžaduje API Key.</li><li>nsfwjs obvykle vyžaduje URL API endpointu.</li><li>Sightengine vyžaduje API user a API secret.</li></ul><p>Vyberte podle účtu, dostupnosti a kvality detekce. Pokud je moderace zapnutá a správně nastavená, ImgBed se pokusí při uploadu zapsat rating obrázku.</p><h2 id="vliv-na-verejnou-galerii" tabindex="-1">Vliv na veřejnou galerii <a class="header-anchor" href="#vliv-na-verejnou-galerii" aria-label="Permalink to &quot;Vliv na veřejnou galerii&quot;">​</a></h2><p>Veřejná galerie filtruje soubory podle režimu přístupu.</p><p>Příklady:</p><ul><li>Adult mode: obrázky R18 se mohou zobrazit.</li><li>Youth mode: obrázky R18 jsou skryté.</li><li>Teen mode: obrázky R16 a R18 jsou skryté.</li><li>Child mode: zobrazují se pouze obrázky General.</li></ul><p>Týká se to jen běžného veřejného přístupu. Administrace stále zobrazuje všechny soubory.</p><h2 id="vliv-na-verejne-url-souboru" tabindex="-1">Vliv na veřejné URL souborů <a class="header-anchor" href="#vliv-na-verejne-url-souboru" aria-label="Permalink to &quot;Vliv na veřejné URL souborů&quot;">​</a></h2><p>Veřejné URL souborů jsou přímé odkazy, které otevírají návštěvníci.</p><p>Pokud je rating souboru povolen aktuálním režimem, ImgBed vrátí původní obrázek.</p><p>Pokud je rating nad povolenou úrovní, běžný veřejný přístup nevrátí původní obrázek. ImgBed místo toho vrátí nastavený blokovaný výsledek nebo náhradní obrázek.</p><p>Příklad:</p><ul><li>Aktuální režim je Child mode.</li><li>Obrázek má rating R18.</li><li>Návštěvník otevře veřejný URL přímo.</li><li>ImgBed tomuto návštěvníkovi nevrátí původní R18 obrázek.</li></ul><p><img src="'+o+'" alt="Omezený obrázek souboru" loading="lazy"></p><p>Administrátorů při prohlížení souborů v administraci se toto omezení netýká.</p><h2 id="vliv-na-random-image-api" tabindex="-1">Vliv na Random Image API <a class="header-anchor" href="#vliv-na-random-image-api" aria-label="Permalink to &quot;Vliv na Random Image API&quot;">​</a></h2><p>Random Image API také filtruje svůj výběr kandidátů podle režimu přístupu.</p><p>V Child mode se náhodné obrázky vybírají jen ze souborů s hodnocením General.</p><p>V Youth mode mohou náhodné obrázky pocházet z General, R12 a R16, ale ne z R18.</p><p>Tím se zabrání tomu, aby Random Image API obcházelo omezení veřejné galerie.</p><h2 id="vztah-k-pravidlum-seznamu" tabindex="-1">Vztah k pravidlům seznamů <a class="header-anchor" href="#vztah-k-pravidlum-seznamu" aria-label="Permalink to &quot;Vztah k pravidlům seznamů&quot;">​</a></h2><p>Access mode není jediné pravidlo veřejného přístupu. Funguje společně s allowlist a blocklist.</p><p>Stručně:</p><ul><li>Obsah na allowlist je veřejný jako první.</li><li>Obsah na blocklist nelze běžnými návštěvníky zobrazit přímo.</li><li>Obsah, který není na žádném seznamu, se následně kontroluje podle access mode.</li></ul><p>Pokud je obrázek omezený ratingem i pravidly seznamů, běžní návštěvníci stále nemohou přímo zobrazit původní soubor.</p><h2 id="doporucena-nastaveni" tabindex="-1">Doporučená nastavení <a class="header-anchor" href="#doporucena-nastaveni" aria-label="Permalink to &quot;Doporučená nastavení&quot;">​</a></h2><p>Pro veřejné weby:</p><ul><li>Zapněte moderaci.</li><li>Vyberte režim přístupu odpovídající publiku webu.</li><li>Pro návštěvníky všech věkových skupin použijte Child mode nebo Teen mode.</li><li>Vyhněte se Adult mode, pokud nechcete veřejně zobrazovat dospělý obsah.</li><li>Kontrolujte ratingy v administraci a podle potřeby je upravujte ručně.</li></ul><p>Pro soukromé nebo osobní weby:</p><ul><li>Adult mode je obvykle v pořádku.</li><li>Zapněte moderaci, pokud je užitečná.</li><li>Ratingy kontrolujte a upravujte v administraci podle potřeby.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="zmizi-soubory-z-administrace-po-zmene-access-mode" tabindex="-1">Zmizí soubory z administrace po změně Access Mode? <a class="header-anchor" href="#zmizi-soubory-z-administrace-po-zmene-access-mode" aria-label="Permalink to &quot;Zmizí soubory z administrace po změně Access Mode?&quot;">​</a></h3><p>Ne.</p><p>Access mode ovlivňuje jen běžný veřejný přístup. Administraci neovlivňuje.</p><h3 id="proc-verejna-galerie-po-prepnuti-na-child-mode-ukazuje-mene-obrazku" tabindex="-1">Proč veřejná galerie po přepnutí na Child mode ukazuje méně obrázků? <a class="header-anchor" href="#proc-verejna-galerie-po-prepnuti-na-child-mode-ukazuje-mene-obrazku" aria-label="Permalink to &quot;Proč veřejná galerie po přepnutí na Child mode ukazuje méně obrázků?&quot;">​</a></h3><p>Child mode dovoluje veřejně zobrazit pouze soubory General. R12, R16 a R18 se filtrují.</p><h3 id="mohou-verejne-url-stale-otevrit-obrazky-pro-dospele" tabindex="-1">Mohou veřejné URL stále otevřít obrázky pro dospělé? <a class="header-anchor" href="#mohou-verejne-url-stale-otevrit-obrazky-pro-dospele" aria-label="Permalink to &quot;Mohou veřejné URL stále otevřít obrázky pro dospělé?&quot;">​</a></h3><p>Pokud aktuální režim takový rating nepovoluje, běžné veřejné URL nevrátí původní obrázek.</p><h3 id="muze-random-image-api-vratit-omezene-obrazky" tabindex="-1">Může Random Image API vrátit omezené obrázky? <a class="header-anchor" href="#muze-random-image-api-vratit-omezene-obrazky" aria-label="Permalink to &quot;Může Random Image API vrátit omezené obrázky?&quot;">​</a></h3><p>Ne.</p><p>Random Image API filtruje kandidáty podle aktuálního režimu přístupu.</p><h3 id="co-se-stane-se-starymi-neohodnocenymi-obrazky" tabindex="-1">Co se stane se starými neohodnocenými obrázky? <a class="header-anchor" href="#co-se-stane-se-starymi-neohodnocenymi-obrazky" aria-label="Permalink to &quot;Co se stane se starými neohodnocenými obrázky?&quot;">​</a></h3><p>Neohodnocené obrázky nejsou automaticky skryté jen proto, že nemají výsledek moderace. Rating jim můžete později upravit v administraci.</p>',67)])])}const b=a(i,[["render",d]]);export{h as __pageData,b as default};
